#include<bits/stdc++.h>
using namespace std;
int n,m,k;
struct Edge
{
    int u,v,id;
}e[2][200010];
int tot[2],fa[200010],flag[200010];
struct node
{
    int u,v,w;
    bool operator<(const node&b)const
    {
        return w>b.w;
    }
}ans[200010],edge[200010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
int main()
{
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=m;i++)
    {
        int u,v,c;
        scanf("%d%d%d",&u,&v,&c);
        c=1-c;
        e[c][++tot[c]]=(Edge){u,v,i};
        edge[i]=(node){u,v,c};
    }
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=tot[0];i++)
    {
        int u=e[0][i].u,v=e[0][i].v;
        if(find(u)!=find(v))
        {
            merge(u,v);
        }
    }
    int cnt=0;
    for(int i=1;i<=tot[1];i++)
    {
        int u=e[1][i].u,v=e[1][i].v;
        if(find(u)!=find(v))
        {
            cnt++;
            flag[i]=1;
            edge[e[1][i].id].w=2;
            merge(u,v);
        }
    }
    if(cnt>k||tot[1]<k)
    {
        printf("no solution");
        return 0;
    }
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
    }
    int anstot=0;
    int cnt1=0,cnt2=0;
    sort(edge+1,edge+1+m);
    for(int i=1;i<=m;i++)
    {
        if(find(edge[i].u)==find(edge[i].v))
        {
            continue;
        }
        if(edge[i].w==0||cnt2<k)
        {
            ans[++anstot]=edge[i];
            if(edge[i].w)
            {
                cnt2++;
            }
            merge(edge[i].u,edge[i].v);
            if(edge[i].w==2)
            {
                cnt1++;
            }
        }
    }
    if(cnt1!=cnt||cnt2!=k)
    {
        printf("no solution");
        return 0;
    }
    for(int i=1;i<=n;i++)
    {
        if(find(i)!=find(1))
        {
            printf("no solution");
            return 0;
        }
    }
    for(int i=1;i<=anstot;i++)
    {
        printf("%d %d %d\n",ans[i].u,ans[i].v,1-min(1,ans[i].w));
    }
    return 0;
}
